//! NetX Duo BSD socket networking for ThreadX.
//!
//! Implements PlatformTcp, PlatformUdp, PlatformSocketHelpers on
//! ThreadxPlatform using NetX Duo's BSD socket API (`nx_bsd_*`).
//!
//! Types and constants are auto-generated by `threadx-netx-sys` (bindgen),
//! eliminating manual constant mismatches (SOL_SOCKET, SO_RCVTIMEO, etc.).

#![allow(unsafe_op_in_unsafe_fn)]

use core::ffi::{c_int, c_void};

use crate::ThreadxPlatform;
use threadx_netx_sys::*;

// ============================================================================
// C struct wrappers matching zenoh-pico's ThreadX platform types
// ============================================================================

/// Socket: `{ int _fd; }` (matches _z_sys_net_socket_t)
#[repr(C)]
struct Socket {
    _fd: c_int,
}

/// Endpoint: `{ uint32_t _addr; uint16_t _port; }` (matches _z_sys_net_endpoint_t)
#[repr(C)]
#[derive(Clone, Copy)]
struct Endpoint {
    _addr: u32, // IPv4 in host byte order
    _port: u16, // port in host byte order
}

/// Phase 71.22 — net buffer sizes (see nros-platform-posix for rationale).
pub const NET_SOCKET_SIZE: usize = core::mem::size_of::<Socket>();
pub const NET_SOCKET_ALIGN: usize = core::mem::align_of::<Socket>();
pub const NET_ENDPOINT_SIZE: usize = core::mem::size_of::<Endpoint>();
pub const NET_ENDPOINT_ALIGN: usize = core::mem::align_of::<Endpoint>();

// ============================================================================
// Helpers
// ============================================================================

/// Parse "a.b.c.d" → host-byte-order u32.
fn parse_ipv4(s: *const u8) -> u32 {
    if s.is_null() {
        return 0;
    }
    let mut octets = [0u32; 4];
    let mut idx = 0usize;
    let mut val: u32 = 0;
    let mut has_digit = false;
    let mut p = s;

    loop {
        let ch = unsafe { *p };
        if ch == 0 {
            break;
        }
        if ch.is_ascii_digit() {
            val = val * 10 + (ch - b'0') as u32;
            has_digit = true;
        } else if ch == b'.' {
            if !has_digit || idx >= 3 {
                return 0;
            }
            octets[idx] = val;
            idx += 1;
            val = 0;
            has_digit = false;
        } else {
            return 0;
        }
        p = unsafe { p.add(1) };
    }

    if !has_digit || idx != 3 {
        return 0;
    }
    octets[3] = val;

    (octets[0] << 24) | (octets[1] << 16) | (octets[2] << 8) | octets[3]
}

fn parse_port(s: *const u8) -> u16 {
    if s.is_null() {
        return 0;
    }
    let mut val: u32 = 0;
    let mut p = s;
    loop {
        let ch = unsafe { *p };
        if ch == 0 {
            break;
        }
        if ch.is_ascii_digit() {
            val = val * 10 + (ch - b'0') as u32;
        } else {
            return 0;
        }
        p = unsafe { p.add(1) };
    }
    val as u16
}

fn ep_to_sockaddr(ep: &Endpoint) -> nx_bsd_sockaddr_in {
    nx_bsd_sockaddr_in {
        sin_family: AF_INET as _,
        sin_port: htons(ep._port),
        sin_addr: nx_bsd_in_addr {
            s_addr: htonl(ep._addr),
        },
        sin_zero: [0; 8],
    }
}

/// Apply `SO_RCVTIMEO` for `timeout_ms` (1+ ms). NetX BSD's
/// `nx_bsd_setsockopt` casts the option buffer directly to
/// `struct nx_bsd_timeval *`, so passing a raw `INT` (the obvious
/// "milliseconds" shape) silently produces a 0-tick option which
/// falls through to `NX_WAIT_FOREVER`. Always pass a real
/// `nx_bsd_timeval`.
fn set_recv_timeout_ms(fd: INT, timeout_ms: u32) {
    let tv = nx_bsd_timeval {
        tv_sec: (timeout_ms / 1000) as nx_bsd_time_t,
        tv_usec: ((timeout_ms % 1000) * 1000) as nx_bsd_suseconds_t,
    };
    unsafe {
        nx_bsd_setsockopt(
            fd,
            SOL_SOCKET as INT,
            SO_RCVTIMEO as INT,
            &tv as *const _ as *const c_void,
            core::mem::size_of::<nx_bsd_timeval>() as INT,
        );
    }
}

// ============================================================================
// TCP
// ============================================================================

impl ThreadxPlatform {
    pub fn tcp_create_endpoint(ep: *mut c_void, address: *const u8, port: *const u8) -> i8 {
        // Phase 97.4.threadx — RTPS binds use "0.0.0.0" (any-iface)
        // for unicast / multicast listeners. `parse_ipv4` returns 0
        // for both that *and* parse failures; we differentiate by
        // checking the literal string. Accept "0.0.0.0\0" as
        // INADDR_ANY, reject any other zero-result as malformed.
        if address.is_null() || port.is_null() {
            return -1;
        }
        let is_any = unsafe {
            *address == b'0'
                && *address.add(1) == b'.'
                && *address.add(2) == b'0'
                && *address.add(3) == b'.'
                && *address.add(4) == b'0'
                && *address.add(5) == b'.'
                && *address.add(6) == b'0'
                && *address.add(7) == 0
        };
        let ep = ep as *mut Endpoint;
        let addr = parse_ipv4(address);
        let p = parse_port(port);
        if addr == 0 && !is_any {
            return -1;
        }
        unsafe {
            (*ep)._addr = addr;
            (*ep)._port = p;
        }
        0
    }

    pub fn tcp_free_endpoint(_ep: *mut c_void) {}

    pub fn tcp_open(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };

        let fd = unsafe { nx_bsd_socket(AF_INET as INT, SOCK_STREAM as INT, IPPROTO_TCP as INT) };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sock)._fd = fd };

        if timeout_ms > 0 {
            set_recv_timeout_ms(fd, timeout_ms);
        }

        let addr = ep_to_sockaddr(rep);
        let rc = unsafe {
            nx_bsd_connect(
                fd,
                &addr as *const nx_bsd_sockaddr_in as *mut nx_bsd_sockaddr,
                core::mem::size_of::<nx_bsd_sockaddr_in>() as INT,
            )
        };
        if rc < 0 {
            unsafe {
                nx_bsd_soc_close(fd);
                (*sock)._fd = -1;
            }
            return -1;
        }

        0
    }

    pub fn tcp_listen(sock: *mut c_void, endpoint: *const c_void) -> i8 {
        let sock = sock as *mut Socket;
        let lep = unsafe { &*(endpoint as *const Endpoint) };

        let fd = unsafe { nx_bsd_socket(AF_INET as INT, SOCK_STREAM as INT, IPPROTO_TCP as INT) };
        if fd < 0 {
            return -1;
        }

        let one: INT = 1;
        unsafe {
            nx_bsd_setsockopt(
                fd,
                SOL_SOCKET as INT,
                SO_REUSEADDR as INT,
                &one as *const _ as *const c_void,
                core::mem::size_of::<INT>() as INT,
            );
        }

        let addr = ep_to_sockaddr(lep);
        if unsafe {
            nx_bsd_bind(
                fd,
                &addr as *const nx_bsd_sockaddr_in as *mut nx_bsd_sockaddr,
                core::mem::size_of::<nx_bsd_sockaddr_in>() as INT,
            )
        } < 0
        {
            unsafe { nx_bsd_soc_close(fd) };
            return -1;
        }

        if unsafe { nx_bsd_listen(fd, 1) } < 0 {
            unsafe { nx_bsd_soc_close(fd) };
            return -1;
        }

        unsafe { (*sock)._fd = fd };
        0
    }

    pub fn tcp_close(sock: *mut c_void) {
        let sock = sock as *mut Socket;
        let fd = unsafe { (*sock)._fd };
        if fd >= 0 {
            unsafe {
                nx_bsd_soc_close(fd);
                (*sock)._fd = -1;
            }
        }
    }

    pub fn tcp_read(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._fd < 0 {
            return usize::MAX;
        }
        let n = unsafe { nx_bsd_recv(sock._fd, buf as *mut _ as *mut _, len as INT, 0) };
        if n <= 0 { usize::MAX } else { n as usize }
    }

    pub fn tcp_read_exact(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._fd < 0 {
            return usize::MAX;
        }
        let mut total: usize = 0;
        while total < len {
            let n = unsafe {
                nx_bsd_recv(
                    sock._fd,
                    buf.add(total) as *mut _ as *mut _,
                    (len - total) as INT,
                    0,
                )
            };
            if n <= 0 {
                return usize::MAX;
            }
            total += n as usize;
        }
        total
    }

    pub fn tcp_send(sock: *const c_void, buf: *const u8, len: usize) -> usize {
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._fd < 0 {
            return usize::MAX;
        }
        let mut total: usize = 0;
        while total < len {
            let n = unsafe {
                nx_bsd_send(
                    sock._fd,
                    buf.add(total) as *const CHAR,
                    (len - total) as INT,
                    0,
                )
            };
            if n <= 0 {
                return usize::MAX;
            }
            total += n as usize;
        }
        total
    }
}

// ============================================================================
// UDP
// ============================================================================

impl ThreadxPlatform {
    pub fn udp_create_endpoint(ep: *mut c_void, address: *const u8, port: *const u8) -> i8 {
        Self::tcp_create_endpoint(ep, address, port)
    }

    pub fn udp_free_endpoint(_ep: *mut c_void) {}

    pub fn udp_open(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };

        let fd = unsafe { nx_bsd_socket(AF_INET as INT, SOCK_DGRAM as INT, IPPROTO_UDP as INT) };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sock)._fd = fd };

        if timeout_ms > 0 {
            set_recv_timeout_ms(fd, timeout_ms);
        }

        // Connect for send/recv
        let addr = ep_to_sockaddr(rep);
        if unsafe {
            nx_bsd_connect(
                fd,
                &addr as *const nx_bsd_sockaddr_in as *mut nx_bsd_sockaddr,
                core::mem::size_of::<nx_bsd_sockaddr_in>() as INT,
            )
        } < 0
        {
            unsafe {
                nx_bsd_soc_close(fd);
                (*sock)._fd = -1;
            }
            return -1;
        }

        0
    }

    /// Phase 71.21 — bind a UDP socket for inbound use via NetX BSD.
    ///
    /// Phase 97.4.threadx-linux: unicast bind path no longer sets
    /// `SO_REUSEADDR`. With it, two co-resident processes both
    /// bound to `INADDR_ANY:default_unicast_port` and the kernel
    /// delivered each datagram to *one* of them — losing every
    /// other RTPS message. Without it, the second process's
    /// `bind(2)` returns `EADDRINUSE` and the
    /// `create_participant` auto-pid loop bumps to the next slot,
    /// giving each participant a unique unicast port. Multicast
    /// binds (`mcast_listen`) layer the option back in via the
    /// dedicated reusable-bind helper below.
    pub fn udp_listen(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        Self::udp_listen_inner(sock, endpoint, timeout_ms, false)
    }

    /// Variant of `udp_listen` that *does* set `SO_REUSEADDR`
    /// before `bind(2)` — used by the multicast listen path so
    /// every co-resident participant can join the same SPDP
    /// group on `239.255.0.1:7400`.
    pub fn udp_listen_reusable(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        Self::udp_listen_inner(sock, endpoint, timeout_ms, true)
    }

    fn udp_listen_inner(
        sock: *mut c_void,
        endpoint: *const c_void,
        timeout_ms: u32,
        reuseaddr: bool,
    ) -> i8 {
        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };

        let fd = unsafe { nx_bsd_socket(AF_INET as INT, SOCK_DGRAM as INT, IPPROTO_UDP as INT) };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sock)._fd = fd };

        if reuseaddr {
            let one: INT = 1;
            unsafe {
                nx_bsd_setsockopt(
                    fd,
                    SOL_SOCKET as INT,
                    SO_REUSEADDR as INT,
                    &one as *const _ as *const c_void,
                    core::mem::size_of::<INT>() as INT,
                );
            }
        }

        if timeout_ms > 0 {
            set_recv_timeout_ms(fd, timeout_ms);
        }

        let addr = ep_to_sockaddr(rep);
        if unsafe {
            nx_bsd_bind(
                fd,
                &addr as *const nx_bsd_sockaddr_in as *mut nx_bsd_sockaddr,
                core::mem::size_of::<nx_bsd_sockaddr_in>() as INT,
            )
        } < 0
        {
            unsafe {
                nx_bsd_soc_close(fd);
                (*sock)._fd = -1;
            }
            return -1;
        }
        0
    }

    pub fn udp_close(sock: *mut c_void) {
        Self::tcp_close(sock);
    }

    pub fn udp_read(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._fd < 0 {
            return usize::MAX;
        }
        let n = unsafe { nx_bsd_recv(sock._fd, buf as *mut _ as *mut _, len as INT, 0) };
        if n <= 0 { usize::MAX } else { n as usize }
    }

    pub fn udp_read_exact(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        Self::udp_read(sock, buf, len)
    }

    pub fn udp_send(
        sock: *const c_void,
        buf: *const u8,
        len: usize,
        endpoint: *const c_void,
    ) -> usize {
        let sock = unsafe { &*(sock as *const Socket) };
        let rep = unsafe { &*(endpoint as *const Endpoint) };
        if sock._fd < 0 {
            return usize::MAX;
        }
        let addr = ep_to_sockaddr(rep);
        let n = unsafe {
            nx_bsd_sendto(
                sock._fd,
                buf as *const _ as *mut _,
                len as INT,
                0,
                &addr as *const nx_bsd_sockaddr_in as *mut nx_bsd_sockaddr,
                core::mem::size_of::<nx_bsd_sockaddr_in>() as INT,
            )
        };
        if n <= 0 { usize::MAX } else { n as usize }
    }

    pub fn udp_set_recv_timeout(sock: *const c_void, timeout_ms: u32) {
        let sock = unsafe { &*(sock as *const Socket) };
        // Phase 97.4.threadx-riscv64 — `timeout_ms == 0` means
        // "cooperative non-blocking" (the recv loop polls every
        // tick). NetX BSD honours `fcntl(F_SETFL, O_NONBLOCK)`
        // (nxd_bsd.c F_SETFL toggles `NX_BSD_SOCKET_ENABLE_OPTION_NON_BLOCKING`
        // on the socket array entry; the recv path checks that flag
        // and falls through to `wait_option = 0`). Use fcntl for the
        // 0-ms path; for non-zero timeouts NetX expects a
        // `nx_bsd_timeval` struct (not a raw INT — the older
        // INT-passing path silently mis-parses the buffer because
        // nxd_bsd.c casts `option_value` directly to
        // `struct nx_bsd_timeval *`).
        if timeout_ms == 0 {
            unsafe {
                let flags = nx_bsd_fcntl(sock._fd, F_GETFL, 0);
                if flags >= 0 {
                    nx_bsd_fcntl(sock._fd, F_SETFL, (flags as u32) | O_NONBLOCK);
                }
            }
        } else {
            set_recv_timeout_ms(sock._fd, timeout_ms);
        }
    }
}

// ============================================================================
// Socket helpers
// ============================================================================

impl ThreadxPlatform {
    pub fn socket_set_non_blocking(sock: *const c_void) -> i8 {
        // NetX Duo's BSD shim does support `fcntl(F_SETFL, O_NONBLOCK)`
        // — it toggles `NX_BSD_SOCKET_ENABLE_OPTION_NON_BLOCKING` on
        // the socket array entry (nxd_bsd.c F_SETFL handler). The
        // earlier "not supported" claim was a misread.
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._fd < 0 {
            return -1;
        }
        unsafe {
            let flags = nx_bsd_fcntl(sock._fd, F_GETFL, 0);
            if flags < 0 {
                return -1;
            }
            if nx_bsd_fcntl(sock._fd, F_SETFL, (flags as u32) | O_NONBLOCK) < 0 {
                return -1;
            }
        }
        0
    }

    pub fn socket_accept(sock_in: *const c_void, sock_out: *mut c_void) -> i8 {
        let sin = unsafe { &*(sock_in as *const Socket) };
        let sout = sock_out as *mut Socket;
        let mut addr: nx_bsd_sockaddr_in = unsafe { core::mem::zeroed() };
        let mut addrlen: INT = core::mem::size_of::<nx_bsd_sockaddr_in>() as INT;

        let fd = unsafe {
            nx_bsd_accept(
                sin._fd,
                &mut addr as *mut nx_bsd_sockaddr_in as *mut nx_bsd_sockaddr,
                &mut addrlen,
            )
        };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sout)._fd = fd };
        0
    }

    pub fn socket_close(sock: *mut c_void) {
        Self::tcp_close(sock);
    }

    pub fn socket_wait_event(_peers: *mut c_void, _mutex: *mut c_void) -> i8 {
        // Phase 77.22: delegate to `PlatformYield::yield_now()`
        // (`tx_thread_relinquish` instead of `tx_thread_sleep(1)`).
        use nros_platform_api::PlatformYield;
        <Self as PlatformYield>::yield_now();
        0
    }
}

// ============================================================================
// UDP multicast — Phase 97.4.threadx
// ============================================================================
//
// NetX Duo's BSD shim exposes a real `IP_ADD_MEMBERSHIP` setsockopt
// (see `nxd_bsd.h:601`). Same shape as the lwIP / NuttX paths:
//   * `mcast_open` — open a regular UDP socket aimed at the mcast
//     group + stash the destination endpoint in `lep` for the
//     writer's reuse.
//   * `mcast_listen` — `udp_listen` + setsockopt
//     `IP_ADD_MEMBERSHIP` + flip O_NONBLOCK when the caller asked
//     for `timeout_ms = 0`.
//   * `mcast_read{,_exact}` / `mcast_send` — delegate to the
//     unicast helpers; once the IGMP join lands NetX delivers the
//     mcast traffic through the same `nx_bsd_recv` path.

impl ThreadxPlatform {
    pub fn mcast_open(
        sock: *mut c_void,
        endpoint: *const c_void,
        lep: *mut c_void,
        timeout_ms: u32,
        _iface: *const u8,
    ) -> i8 {
        if !lep.is_null() && !endpoint.is_null() {
            unsafe {
                core::ptr::copy_nonoverlapping(
                    endpoint as *const u8,
                    lep as *mut u8,
                    core::mem::size_of::<Endpoint>(),
                );
            }
        }
        Self::udp_open(sock, endpoint, timeout_ms)
    }

    pub fn mcast_listen(
        sock: *mut c_void,
        endpoint: *const c_void,
        timeout_ms: u32,
        _iface: *const u8,
        _join: *const u8,
    ) -> i8 {
        // Mcast bind path keeps `SO_REUSEADDR` so multiple
        // co-resident participants can all join the same SPDP
        // group. The unicast `udp_listen` deliberately drops it
        // (see Phase 97.4.threadx-linux comment there).
        let rc = Self::udp_listen_reusable(sock, endpoint, timeout_ms);
        if rc < 0 {
            return rc;
        }

        let sock_ref = unsafe { &*(sock as *const Socket) };
        let fd = sock_ref._fd;
        if fd < 0 {
            return -1;
        }

        // Phase 97.4.threadx — IGMP join path. We try the BSD-shim
        // setsockopt(IP_ADD_MEMBERSHIP) but tolerate failure: on
        // QEMU virtio-net + the NetX virtio-net-netx driver the
        // hardware filter accepts all mcast (`NX_LINK_MULTICAST_JOIN`
        // is silently no-op), and the host-side `-netdev socket,mcast`
        // tunnel forwards mcast frames to every joined sibling
        // regardless of the in-VM IGMP state. On the threadx-linux
        // (NSOS) path the same setsockopt forwards to the host kernel
        // (`translate_sockopt` adjusts the constants); host-kernel
        // IGMP membership on loopback is what matters there. Skipping
        // a hard-error rc means a mis-configured `nx_igmp_enable` on
        // the board crate doesn't kill the whole listener.
        if !_join.is_null() {
            let group_h = parse_ipv4(_join);
            if group_h != 0 {
                let group_n = group_h.to_be();
                let mreq = nx_bsd_ip_mreq {
                    imr_multiaddr: nx_bsd_in_addr { s_addr: group_n },
                    imr_interface: nx_bsd_in_addr { s_addr: 0 },
                };
                let _ = unsafe {
                    nx_bsd_setsockopt(
                        fd,
                        IPPROTO_IP as INT,
                        IP_ADD_MEMBERSHIP as INT,
                        &mreq as *const _ as *const c_void,
                        core::mem::size_of::<nx_bsd_ip_mreq>() as INT,
                    )
                };
                // Best-effort — discard rc.
            }
        }

        // Phase 97.4.threadx-riscv64 — `timeout_ms == 0` means the
        // caller wants a cooperative non-blocking recv loop. Earlier
        // bring-up tried `setsockopt(SO_RCVTIMEO, INT 1ms)` which
        // is a buffer-shape mismatch (nxd_bsd.c casts option_value
        // straight to `struct nx_bsd_timeval *`) and silently set
        // option_receive_timeout to 0 → wait_option falls through to
        // `NX_WAIT_FOREVER` → the mcast recv loop blocks the entire
        // app thread forever, which hangs the cooperative drain
        // loop. Use `fcntl(F_SETFL, O_NONBLOCK)` instead — nxd_bsd.c
        // F_SETFL flips `NX_BSD_SOCKET_ENABLE_OPTION_NON_BLOCKING`
        // on the socket entry, and the recv path honours that flag.
        if timeout_ms == 0 {
            unsafe {
                let flags = nx_bsd_fcntl(fd, F_GETFL, 0);
                if flags >= 0 {
                    nx_bsd_fcntl(fd, F_SETFL, (flags as u32) | O_NONBLOCK);
                }
            }
        }
        0
    }

    pub fn mcast_close(
        sockrecv: *mut c_void,
        socksend: *mut c_void,
        _rep: *const c_void,
        _lep: *const c_void,
    ) {
        if !sockrecv.is_null() {
            Self::udp_close(sockrecv);
        }
        if !socksend.is_null() {
            Self::udp_close(socksend);
        }
    }

    pub fn mcast_read(
        sock: *const c_void,
        buf: *mut u8,
        len: usize,
        _lep: *const c_void,
        _addr: *mut c_void,
    ) -> usize {
        Self::udp_read(sock, buf, len)
    }

    pub fn mcast_read_exact(
        sock: *const c_void,
        buf: *mut u8,
        len: usize,
        _lep: *const c_void,
        _addr: *mut c_void,
    ) -> usize {
        Self::udp_read_exact(sock, buf, len)
    }

    pub fn mcast_send(
        sock: *const c_void,
        buf: *const u8,
        len: usize,
        endpoint: *const c_void,
    ) -> usize {
        Self::udp_send(sock, buf, len, endpoint)
    }
}

// ============================================================================
// Trait impls (Phase 84.F4.4)
// ============================================================================
//
// Delegate to the inherent methods above. Every shim dispatch goes through
// these traits (`<ConcretePlatform as PlatformTcp>::open(...)`) so a
// trait-method rename or addition produces a compile error here instead of
// a silent link failure. The inherent methods are kept (rather than
// collapsed into the trait bodies) so that internal `Self::tcp_read` /
// `Self::udp_send` / ... calls in this file keep working unchanged.

impl nros_platform_api::PlatformTcp for ThreadxPlatform {
    fn create_endpoint(ep: *mut c_void, address: *const u8, port: *const u8) -> i8 {
        Self::tcp_create_endpoint(ep, address, port)
    }
    fn free_endpoint(ep: *mut c_void) {
        Self::tcp_free_endpoint(ep)
    }
    fn open(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        Self::tcp_open(sock, endpoint, timeout_ms)
    }
    fn listen(sock: *mut c_void, endpoint: *const c_void) -> i8 {
        Self::tcp_listen(sock, endpoint)
    }
    fn close(sock: *mut c_void) {
        Self::tcp_close(sock)
    }
    fn read(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        Self::tcp_read(sock, buf, len)
    }
    fn read_exact(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        Self::tcp_read_exact(sock, buf, len)
    }
    fn send(sock: *const c_void, buf: *const u8, len: usize) -> usize {
        Self::tcp_send(sock, buf, len)
    }
}

